if cut_y < tree.base_y || cut_y >= tree.base_y.saturating_add(tree.trunk_height) {
    return Err(NicechunkChunkError::GeneratedBlockMismatch);
}

let top_y = surface.saturating_add(TREE_MAX_BLOCK_HEIGHT_ABOVE_SURFACE);
let mut blocks = Vec::with_capacity(TREE_FELL_MAX_BLOCKS);
for y in cut_y..=top_y {
    for z in
        cut_z.saturating_sub(TREE_MAX_LEAF_RADIUS)..=cut_z.saturating_add(TREE_MAX_LEAF_RADIUS)
    {
        for x in cut_x.saturating_sub(TREE_MAX_LEAF_RADIUS)
            ..=cut_x.saturating_add(TREE_MAX_LEAF_RADIUS)
        {
            let tree_block = generated_tree_volume_block(global_config, &tree, x, y, z);
            if tree_block == BLOCK_AIR {
                continue;
            }

if block.world_x == args.world_x
    && block.world_y == args.world_y
    && block.world_z == args.world_z
{
    let data = account.try_borrow_data()?;
    ChunkBrokenState::validate_header(&data, global_config_view.min_build_y)?;
    if ChunkBrokenState::contains_packed(&data, packed)? {
        return Err(NicechunkChunkError::BlockAlreadyMined.into());
    }
}

blocks.push(block);
if (isSupportAnchoredBlock(block, options)) return { blocks: [], supported: true };

for (const [dx, dy, dz] of FACE_OFFSETS) {
  const nx = block.worldX + dx;
  const ny = block.worldY + dy;
  const nz = block.worldZ + dz;
  if (!isWithinBounds(nx, ny, nz, bounds)) {
    return { blocks: [], supported: true };
  }
  const next = supportCollapseBlockAt(nx, ny, nz, plannedRemoved, bounds, options);
  if (!next) {
    if (isSupportAnchorCell(nx, ny, nz, plannedRemoved, options)) return { blocks: [], supported: true };
    continue;
  }

for (const collapseBlock of batch) {
  const mineWithReward = selectedRewardKeySet.has(minedBlockKey(collapseBlock));
  tx.add(mineWithReward
    ? createMineBlockWithRewardsInstruction({
        authority: session.keypair.publicKey,
        block: collapseBlock,
        owner: provider.publicKey,
        backpack: equippedBackpack.publicKey,
        expectedBlockId: collapseBlock.blockId,
        context,
      })
    : createMineBlockInstruction({
        authority: session.keypair.publicKey,
        block: collapseBlock,
        owner: provider.publicKey,
        expectedBlockId: collapseBlock.blockId,
        context,
      }));
}

let recoveredCount = 0;
for (const block of batch) {
  try {
    const result = await submitBatch([block]);
    confirmed.push({ block, result, retried: true });
    recoveredCount += 1;
  } catch (error) {
    failures.push({ block, error });
  }
}

// Two independent failures normally indicate an expired session, RPC
// outage, or another batch-wide fault. Do not fan that out to 48 calls.
if (recoveredCount === 0) {
  for (const remaining of batches.slice(batchIndex + 1).flat()) {
    aborted.push({ block: remaining, error: batchError, reason: "batch-wide-failure" });
  }
  break;
}

const previousCount = Math.max(1, Math.trunc(Number(pending.minedBlockCount) || originalBlocks.length || 1));
const chainConfirmedBlocks = Array.isArray(chainResult?.confirmedBlocks) ? chainResult.confirmedBlocks : [];
let confirmedBlocks = originalBlocks;
if (chainConfirmedBlocks.length) {
  const confirmedKeys = new Set(chainConfirmedBlocks.map(blockKey).filter(Boolean));
  confirmedBlocks = originalBlocks.filter((block) => confirmedKeys.has(blockKey(block)));
  if (!confirmedBlocks.length) return { changed: false, droppedCount: 0, confirmedCount: 0 };
  const confirmedKeySet = new Set(confirmedBlocks.map(blockKey));
  pending.blocks = confirmedBlocks.map((block) => ({ ...block }));
  pending.pendingDeltas = (Array.isArray(pending.pendingDeltas) ? pending.pendingDeltas : [])
    .filter((delta) => confirmedKeySet.has(blockKey(delta)))
    .map((delta) => ({ ...delta }));
  pending.collapseBlocks = (Array.isArray(pending.collapseBlocks) ? pending.collapseBlocks : [])
    .filter((block) => confirmedKeySet.has(blockKey(block)))
    .map((block) => ({ ...block }));
  pending.minedBlockCount = confirmedBlocks.length;
}
